// Split AI Agent output into multiple short messages
// Splits on double newline (\n\n) — agent should separate thoughts with blank lines

const agentOutput = $input.first().json.output || "";
const accountId = $('Prepare Field Edits').first().json.account_id;
const conversationId = $('Prepare Field Edits').first().json.conversation_id;
// ⚙️ CONFIGURE: Replace with your Chatwoot API access token
const chatwootToken = "Your_API_Access_Token_Here";
// ⚙️ CONFIGURE: Replace with your Chatwoot instance URL (no trailing slash)
const chatwootBaseUrl = "https://your-chatwoot-url.com";

// Split on double newlines, filter out empty chunks
const chunks = agentOutput
  .split(/\n\n+/)
  .map(c => c.trim())
  .filter(c => c.length > 0);

const results = [];

for (const chunk of chunks) {
  const response = await this.helpers.httpRequest({
    method: "POST",
    url: `${chatwootBaseUrl}/api/v1/accounts/${accountId}/conversations/${conversationId}/messages`,
    headers: {
      "api_access_token": chatwootToken,
      "Content-Type": "application/json"
    },
    body: {
      content: chunk,
      message_type: "outgoing"
    },
    json: true
  });

  results.push({
    json: {
      chunk,
      message_id: response.id || null,
      success: true
    }
  });

  // Small delay between messages to preserve order in Chatwoot
  await new Promise(resolve => setTimeout(resolve, 300));
}

return results;

