const agents = $input.all().map(item => item.json);

const onlineAgents = agents.filter(
  agent => agent.availability_status === "online"
);

if (onlineAgents.length > 0) {
  const randomAgent =
    onlineAgents[Math.floor(Math.random() * onlineAgents.length)];

  return [
    {
      json: {
        agent_online: "yes",
        assignee_id: randomAgent.id // ✅ renamed here
      }
    }
  ];
}

return [
  {
    json: {
      agent_online: "no"
    }
  }
];
